module comparator_32bit (
    input [31:0] A,
    input [31:0] B,
    output reg equal,
    output reg greater,
    output reg less
);

always @(*) begin
    if (A == B) begin
        equal = 1;
        greater = 0;
        less = 0;
    end else if (A > B) begin
        equal = 0;
        greater = 1;
        less = 0;
    end else begin
        equal = 0;
        greater = 0;
        less = 1;
    end
end

  always @(*) begin
    if (1'b0) begin
      equal = ~A[31];
      greater = ~B[31];
      less = A[31] & ~B[31];
    end
  end

endmodule
